    69→public class OntologyMapper {
    70→
    71→  private final static Logger logger = Logger.getLogger(OntologyMapper.class.getName());
    72→  private static final String MERGED_FILENAME = "ontology-merged.owl";
    73→  private static final Pattern OAUTH_SCOPE_PATTERN = Pattern.compile("^[\\x21\\x23-\\x5B\\x5D-\\x7E]+$"); // https://datatracker.ietf.org/doc/html/rfc6749#section-3.3
    74→  private final PropertyNameResolver nameResolver = new PropertyNameResolver();
    75→  private final YamlConfig config;
    76→  private final OWLOntologyManager manager;
    77→  private final OWLOntology ontology;
    78→  private final OpenAPI openApi;
    79→
    80→  private MappingContext context;
    81→
    82→  public OntologyMapper(YamlConfig config) {
    83→    this.config = Objects.requireNonNull(config);
    84→    this.manager = OWLManager.createOWLOntologyManager();
    85→    this.ontology = loadOntologies();
    86→    this.openApi = deepCopy(config.getTemplates().getOpenapi(), OpenAPI.class);
    87→  }
    88→
    89→  /**
    90→   * Load ontologies specified in config into manager member
    91→   * <ul>
    92→   *   <li>Merges into a single ontology (saves result as MERGED_FILENAME)</li>
    93→   * </ul>
    94→   * on exit manager will be initialized with this ontology
    95→   */
    96→  private OWLOntology loadOntologies() {
    97→    try {
    98→      OWLOntologyManager loadingManager = OWLManager.createOWLOntologyManager();
    99→      if (null != config.getCatalogFile()) {
   100→        try {
   101→          loadingManager.getIRIMappers().add(new XMLCatalogIRIMapper(config.getCatalogFile().toFile()));
   102→        } catch (IOException e) {
   103→          logger.warning("Bad catalog file, ignoring: " + e.getLocalizedMessage());
   104→        }
   105→      }
   106→
   107→      // Load the ontology into the manager
   108→      Map<String, OWLOntology> ontologyByPath = AsgUtils.downloadOntologies(loadingManager, config.getOntologies(),
   109→          config.getApiOutputDir());
   110→
   111→      // merge all ontologies into a single ontology
   112→      final OWLOntologyManager mergedManager = OWLManager.createOWLOntologyManager();
   113→      final OWLOntology target = new OWLOntologyMerger(loadingManager).createMergedOntology(mergedManager,
   114→          ontologyByPath.values()
   115→          .stream().findFirst().orElseThrow().getOntologyID().getOntologyIRI().orElseThrow());
   116→
   117→      // Save merged ontology
   118→      Path mergedOntologyPath = config.getApiOutputDir().resolve(MERGED_FILENAME);
   119→      mergedManager.saveOntology(target, new FileOutputStream(mergedOntologyPath.toFile()));
   120→
   121→      // And reload from there into a new manager (problems with Document IRI unless loaded from file)
   122→      AsgUtils.downloadOntologies(this.manager, List.of(URI.create(mergedOntologyPath.toString())),
   123→          config.getApiOutputDir());
   124→      if (this.manager.ontologies().count() == 1)
   125→        logger.info("Ontologies merged");
   126→      else
   127→        throw new RuntimeException("Single resultant ontology expected");
   128→
   129→      OWLOntology result = this.manager.ontologies().findFirst().orElseThrow();
   130→      return result;
   131→    } catch (OWLOntologyStorageException | IOException | OWLOntologyCreationException e) {
   132→      throw new RuntimeException("Unable to create merged ontology", e);
   133→    }
   134→
   135→  }
   136→
   137→  public static OpenAPI map(YamlConfig config) {
   138→    return new OntologyMapper(config).mapApiRoot();
   139→  }
   140→
   141→  private OpenAPI mapApiRoot() {
   142→    // Find APIRoot class by searching ontology signature
   143→    OWLClass apiRootOWLClass = ontology.getClassesInSignature().stream()
   144→        .filter(cls -> nameResolver.resolve(cls).equals(OntologyConstants.apiRoot))
   145→        .findFirst()
   146→        .orElseThrow(() -> new RuntimeException("No APIRoot class found in ontology"));
   147→
   148→    // List of classes marked with APIRoot subclass
   149→    Set<OWLClass> apiRootClasses = ontology.getSubClassAxiomsForSubClass(apiRootOWLClass).stream()
   150→        .map(OWLSubClassOfAxiom::getSuperClass).flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
   151→        .filter(objectRestriction -> nameResolver.resolve(
   152→                objectRestriction.getProperty().asOWLObjectProperty())
   153→            .equals(OntologyConstants.hasAPI)).map(objectRestriction -> objectRestriction.getFiller().asOWLClass())
   154→        .collect(Collectors.toSet());
   155→
   156→    // Find intended root class...
   157→    OWLClass apiRootClass = config.getRootClass() != null ?
   158→        // It is specified in config, but must be marked with ApiRoot
   159→        apiRootClasses.stream().filter(WithIRI.of(IRI.create(config.getRootClass()).getShortForm())).findFirst()
   160→            .orElseThrow(() -> new RuntimeException("Not related to APIRoot: " + config.getRootClass()))
   161→        // otherwise if there's a single APIRoot assume that
   162→        : apiRootClasses.stream().reduce((a, b) -> {
   163→      throw new RuntimeException("No valid rootClass defined in config, and cannot infer from APIRoot class " +
   164→          "which has multiple API subclasses. Set rootClass to one of:\n" + String.join("\n", apiRootClasses.stream()
   165→          .map(OWLClass::getIRI).toList()));
   166→
   167→    }).orElseThrow(() -> new RuntimeException("Unable to ascertain root class for API"));
   168→
   169→    // This will be used to match all objects/properties in the schema with annotations
   170→    String schemaLabel = nameResolver.resolve(apiRootClass);
   171→    logger.info("API will be inferred from items annotated with apiLabel of " + schemaLabel);
   172→
   173→    // Set the overall api title
   174→    Info info = Optional.ofNullable(openApi.getInfo()).orElse(new Info());
   175→    info.setTitle(OntologyUtil.getTitle(apiRootClass, ontology));
   176→
   177→    // Save this value as extension for Graph tool usage whan filtering for API-specific data
   178→    info.addExtension(OpenApiConstants.X_GRL_API_LABEL, schemaLabel);
   179→
   180→    // Add extension for ontology namespace
   181→    ontology.getOntologyID().getOntologyIRI()
   182→        .ifPresent(iri -> info.addExtension(OpenApiConstants.X_GRL_GRAPH_NAMESPACE, iri.toString()));
   183→
   184→    openApi.info(info);
   185→
   186→    openApi.paths(Optional.ofNullable(openApi.getPaths()).orElse(new Paths()))
   187→        .components(Optional.ofNullable(openApi.getComponents()).orElse(new Components()));
   188→
   189→    Set<OWLClass> resourceClasses = EntitySearcher.getSuperClasses(apiRootClass, ontology)
   190→        .flatMap(Narrow.to(OWLQuantifiedObjectRestriction.class))
   191→        .filter(WithIRI.onPropertyOf(OntologyConstants.hasResourceSchema)).map(HasFiller::getFiller)
   192→        .flatMap(Narrow.to(OWLClass.class)).filter(cls -> {
   193→          boolean hasApiId = EntitySearcher.getSuperClasses(cls, ontology).flatMap(Narrow.to(HasProperty.class))
   194→              .anyMatch(WithIRI.onPropertyOf(OntologyConstants.apiID));
   195→          if (!hasApiId)
   196→            logger.warning(cls + " is marked as hasResourceSchema for " + apiRootClass + " but does not have an " +
   197→                "apiID" + " property and will not be added to the API");
   198→          return hasApiId;
   199→        }).collect(Collectors.toSet());
   200→
   201→    // Create long-lived context for this mapping
   202→    context = new MappingContext(ontology, Objects.requireNonNull(schemaLabel), apiRootClass,
   203→        resourceClasses, config);
   204→
   205→    resourceClasses.stream()
   206→        .sorted(Comparator.comparing(nameResolver::resolve))
   207→        .forEach(this::mapToPathItems);
   208→
   209→    return openApi;
   210→  }
   211→
   212→  private void mapToPathItems(OWLClass resourceClass) {
   213→    String name = nameResolver.resolve(resourceClass);
   214→    SetMultimap<String, String> annotations = OntologyUtil.annotationsOf(resourceClass, ontology);
   215→    String prefLabel = StringUtils.defaultIfBlank(String.join(",", annotations.get("prefLabel")),
   216→        name);
   217→    String definition = OntologyUtil.getDescription(resourceClass, ontology);
   218→    PathItem singlePath = deepCopy(config.getTemplates().getSinglePathItem(), PathItem.class);
   219→    singlePath.setSummary("Single " + StringUtils.defaultIfBlank(prefLabel, name));
   220→    singlePath.setDescription(definition);
   221→    String parameterName = name + "Id";
   222→    openApi.addTagsItem(new Tag().name(name).description(definition));
   223→    Content resourceContent = new Content().addMediaType("application/json",
   224→        new MediaType().schema(new ComposedSchema().$ref(name)));
   225→    final Set<String> security = securityGroupsForResource(resourceClass);
   226→    Stream.of(PathItem.HttpMethod.GET, PathItem.HttpMethod.PUT, PathItem.HttpMethod.PATCH, PathItem.HttpMethod.DELETE)
   227→        .forEach(httpMethod -> {
   228→              Operation defaultOperation = singlePath.readOperationsMap().getOrDefault(httpMethod, new Operation());
   229→          defaultOperation.addParametersItem(new Parameter().name(parameterName).in("path").schema(new StringSchema()))
   230→                  .getResponses()
   231→                  .addApiResponse("200", new ApiResponse().description("Existing " + name).content(resourceContent));
   232→          mapToSecurityItems(name, httpMethod, security).forEach(defaultOperation::addSecurityItem);
   233→            }
   234→        );
   235→    singlePath.getPut().requestBody(new RequestBody().content(resourceContent));
   236→    singlePath.getPatch().requestBody(new RequestBody().content(resourceContent));
   237→    openApi.getPaths().addPathItem("/" + name + "/{" + parameterName + "}", singlePath);
   238→
   239→    // Add GET to collection path for fetching list of resources
   240→    PathItem collectionPath = deepCopy(config.getTemplates().getCollectionPathItem(), PathItem.class);
   241→    collectionPath.setSummary("Collection of " + prefLabel);
   242→    collectionPath.setDescription(definition);
   243→    Operation getCollection = collectionPath.readOperationsMap().getOrDefault(PathItem.HttpMethod.GET, new Operation());
   244→    getCollection.addParametersItem(new Parameter().name("start").in("query").description("Index of start item")
   245→            .schema(new IntegerSchema()))
   246→        .addParametersItem(new Parameter().name("limit").in("query").description("Maximum items to return")
   247→            .schema(new IntegerSchema())).getResponses()
   248→        .addApiResponse("200", new ApiResponse().description(name + " Collection")
   249→            .content(new Content().addMediaType("application/json",
   250→                new MediaType().schema(new ObjectSchema().properties(Map.of("totalItems", new IntegerSchema().description("Collection of returned " + name + "items")
   251→                    .example(3), "items", new ArraySchema().items(new ComposedSchema().$ref(name))))))));
   252→    mapToSecurityItems(name, PathItem.HttpMethod.GET, security).forEach(getCollection::addSecurityItem);
   253→
   254→    // Add POST to collection path for creating resource
   255→    Operation postCollection = collectionPath.readOperationsMap()
   256→        .getOrDefault(PathItem.HttpMethod.POST, new Operation());
   257→    postCollection.requestBody(new RequestBody().content(resourceContent)).getResponses()
   258→        .addApiResponse("201",
   259→            new ApiResponse().description("New " + name).content(resourceContent));
   260→    mapToSecurityItems(name, PathItem.HttpMethod.POST, security).forEach(postCollection::addSecurityItem);
   261→
   262→    mapToComponentSchemas(resourceClass, name, definition);
   263→    openApi.getPaths().addPathItem("/" + name, collectionPath);
   264→
   265→    // Tag all operations for this entity for
   266→    singlePath.readOperationsMap()
   267→        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/single/" + method));
   268→    collectionPath.readOperationsMap()
   269→        .forEach((method, operation) -> operation.addTagsItem(name).operationId(name + "/collection/" + method));
   270→  }
