   272→  /**
   273→   * Determine the security groups associated with the given resource class. If security annotations are present on the
   274→   * resource class's restriction for this API they are returned, otherwise a default group of the form
   275→   * apiName:resourceName is returned
   276→   *
   277→   * @param resourceClass class representing api resource
   278→   * @return set of groups found
   279→   */
   280→  private Set<String> securityGroupsForResource(OWLClass resourceClass) {
   281→    return ontology.subClassAxiomsForSubClass(context.getApiRootClass())
   282→        .filter(owlSubClassOfAxiom -> owlSubClassOfAxiom.getSuperClass() instanceof OWLQuantifiedObjectRestriction restriction && restriction.getFiller()
   283→            .isOWLClass() && restriction.getFiller().asOWLClass().equals(resourceClass)
   284→            && nameResolver.resolve(restriction.getProperty()
   285→                .asObjectPropertyExpression().getNamedProperty())
   286→            .equals(OntologyConstants.hasResourceSchema)).findFirst()
   287→        .map(owlSubClassOfAxiom -> OntologyUtil.annotationsOf(owlSubClassOfAxiom).get(OntologyConstants.security))
   288→        .orElse(Collections.emptySet());
   289→
   290→  }
   291→
   292→  /**
   293→   * Return security items, if any, to associate with a method of the given type for a resource. Each security
   294→   * annotation will generate a security requirement in the api spec for each method. Template from
   295→   * config.securityTemplate will be used to generate the security requirement.<br/>
   296→   * If there is no security scheme in effect, or of no groups are given this stream will be empty, and the
   297→   * defaultSecurityTemplate value will be used from the config<br/>
   298→   * security requirements can contain placeholders which will be replaced in the generated openapi spec:
   299→   * {api} the name of the api (config.name)
   300→   * {action} mapped for each http method being generated from the config.securityActionMappings
   301→   * {model} The resource (model) name for each api resource being generated
   302→   * {security} the security string as obtained from the "security" annotation
   303→   *
   304→   * @param name  name of resource being mapped
   305→   * @param method   being mapped
   306→   * @param security groups the resource belongs to
   307→   * @return SecurityItems
   308→   */
   309→  private Stream<SecurityRequirement> mapToSecurityItems(String name, PathItem.HttpMethod method,
   310→                                                         Set<String> security) {
   311→    // If apiKey is enabled, add this as a requirement
   312→    Stream.Builder<SecurityRequirement> requirements = Stream.builder();
   313→    config.getApiKeySecuritySchemaName()
   314→        .ifPresent(s -> requirements.add(new SecurityRequirement().addList(s)));
   315→
   316→    // oauth2 scheme - add requirment groups for these
   317→    config.getOAuth2SecuritySchemeName().ifPresent(oauthSchemeName -> {
   318→      String template =
   319→          security.isEmpty() ? config.getDefaultSecurityTemplate() : config.getSecurityTemplate();
   320→      if (StringUtils.isEmpty(template)) {
   321→        // no scoped requirements, auth alone is sufficient
   322→        requirements.add(new SecurityRequirement().addList(oauthSchemeName));
   323→      } else {
   324→        // Map scoped requirements
   325→        Map<String, String> replacements = Map.of("api", config.getName(), // name of api
   326→            "action", config.getSecurityActionMappings()
   327→                .getOrDefault(method, ""), // action, mapped from path's http method,
   328→            "model", name // current path's model/resource
   329→        );
   330→        List<String> securityRequirements =
   331→            Stream.of(security, // multiple security names maye be provided
   332→                    List.of("") // non if default
   333→                ).flatMap(Collection::stream)
   334→                .map(s -> new StringSubstitutor(
   335→                    key -> key.equals("security") ? s : replacements.getOrDefault(key, ""), "{",
   336→                    "}", '\'').setEnableSubstitutionInVariables(
   337→                        true) // security annotations can contain replacements
   338→                    .replace(template)).filter(requirement -> {
   339→                  boolean valid = OAUTH_SCOPE_PATTERN.matcher(requirement).matches();
   340→                  if (!valid) {
   341→                    logger.warning(String.format(
   342→                        "%s (%s) security requirement generated ignored (must match " + "https" +
   343→                            "://datatracker.ietf.org/doc/html/rfc6749#section-3.3 scope_token): %s",
   344→                        name, method, requirement));
   345→                  }
   346→                  return valid;
   347→                }).toList();
   348→        securityRequirements.stream().map(
   349→            securityRequirement -> new SecurityRequirement().addList(oauthSchemeName,
   350→                securityRequirement)).forEach(requirements::add);
   351→      }
   352→    });
   353→    return requirements.build();
   354→  }
   355→
   356→  private void mapToComponentSchemas(OWLClass resourceClass, String name, String definition) {
   357→
   358→    ResourceSchemaMapper schemaMapper = new ResourceSchemaMapper(context, resourceClass, definition);
   359→    Map<String, Schema> schemas = openApi.getComponents()
   360→        .schemas(Optional.ofNullable(openApi.getComponents().getSchemas()).orElse(new LinkedHashMap<>())).getSchemas();
   361→    schemas.put(name, schemaMapper.getSchema());
   362→    schemas.putAll(context.getSchemaByRef());
   363→  }
   364→
   365→  private static <T> T deepCopy(T src, Class<T> cls) {
   366→    ObjectMapper mapper = Json.mapper().setSerializationInclusion(Include.NON_NULL);
   367→    try {
   368→      return mapper.readValue(mapper.writeValueAsString(src), cls);
   369→    } catch (JsonProcessingException e) {
   370→      throw new RuntimeException(e);
   371→    }
   372→  }
   373→}
