    59→  /**
    60→   * If not in context cache already, create schema for given class and add to cache
    61→   *
    62→   * @param cls OWL class to add schema for
    63→   */
    64→  public void addSchema(OWLClass cls) {
    65→    String shortName = nameResolver.resolve(cls);
    66→    schemaByRef.computeIfAbsent(shortName, s -> {
    67→      if (!computing.contains(s)) {
    68→        computing.add(s);
    69→        try {
    70→          String description = OntologyUtil.getDescription(cls, ontology);
    71→          ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    72→          return resourceSchemaMapper.getSchema();
    73→        } finally {
    74→          computing.remove(s);
    75→        }
    76→      } else
    77→        return null; // already being computed, ignore to avoid infinite recursion
    78→    });
    79→  }
    80→
    81→  public Set<OWLClass> getResourceClasses() {
    82→    return resourceClasses;
    83→  }
    84→
    85→  /**
    86→   * Returns the maximum depth for expanding object property assertions on Pattern B taxonomy
    87→   * individuals.
    88→   *
    89→   * @return the maximum individual depth from config
    90→   */
    91→  public int getMaxIndividualDepth() {
    92→    return config.getMaxIndividualDepth();
    93→  }
    94→}
