   109→   * between configs
   110→   */
   111→  interface MergableOpenApi {
   112→    @JsonMerge
   113→    Components getComponents();
   114→
   115→    @JsonMerge
   116→    Info getInfo();
   117→
   118→    @JsonMerge
   119→    io.swagger.v3.oas.models.Paths getPaths(); // this doesn't seem to work for Map-based property, though not needed at present, may be fixed by https://github.com/FasterXML/jackson-databind/issues/4922
   120→
   121→    @JsonMerge
   122→    List<SecurityRequirement> getSecurity();
   123→  }
   124→
   125→}
